os.makedirs(UPLOAD_DIR, exist_ok=True)

face_model = {
    "classifier": None,
    "label_encoder": None,
    "known_encodings": [],
    "known_labels": [],
    "is_trained": False
}


class TrainingStatus(BaseModel):
    status: str
    num_employees: int
    num_images: int
    employees: list[str]


class RecognitionResult(BaseModel):
    success: bool
    num_faces_detected: int
    timestamp: str
    results: list[dict]


class EmployeeRegistration(BaseModel):
    employee_id: str
    employee_name: str


def load_model():
    """Load pre-trained model if it exists."""
    if os.path.exists(MODEL_PATH) and os.path.exists(ENCODER_PATH) and os.path.exists(ENCODINGS_PATH):
        try:
            with open(MODEL_PATH, "rb") as f:
                face_model["classifier"] = pickle.load(f)
            with open(ENCODER_PATH, "rb") as f:
                face_model["label_encoder"] = pickle.load(f)
            with open(ENCODINGS_PATH, "rb") as f:
                data = pickle.load(f)
                face_model["known_encodings"] = data["encodings"]
                face_model["known_labels"] = data["labels"]
            face_model["is_trained"] = True
            logger.info("Model loaded successfully")
        except Exception as e:
            logger.error(f"Error loading model: {e}")
            face_model["is_trained"] = False


def save_model():
    """Save trained model to disk."""
    with open(MODEL_PATH, "wb") as f:
        pickle.dump(face_model["classifier"], f)
    with open(ENCODER_PATH, "wb") as f:
        pickle.dump(face_model["label_encoder"], f)
    with open(ENCODINGS_PATH, "wb") as f:
        pickle.dump({
            "encodings": face_model["known_encodings"],
            "labels": face_model["known_labels"]
        }, f)
    logger.info("Model saved successfully")


def encode_face_from_file(file_path: str) -> list[np.ndarray]:
    """Extract face encodings from an image file."""
    image = face_recognition.load_image_file(file_path)
    face_locations = face_recognition.face_locations(image, model="hog")
    face_encodings = face_recognition.face_encodings(image, face_locations)
    return face_encodings, face_locations


