@app.post("/employees/register")
async def register_employee(employee_id: str, employee_name: str):
    """Register a new employee by creating their directory."""
    employee_dir = os.path.join(TRAINING_DIR, f"{employee_id}_{employee_name}")
    if os.path.exists(employee_dir):
        return {"status": "exists", "message": f"Employee {employee_name} already registered", "directory": employee_dir}
    os.makedirs(employee_dir, exist_ok=True)
    return {
        "status": "registered",
        "employee_id": employee_id,
        "employee_name": employee_name,
        "directory": employee_dir,
        "message": "Upload training photos using /employees/upload-photo endpoint"
    }


@app.post("/employees/upload-photo")
async def upload_employee_photo(
    employee_id: str,
    employee_name: str,
    photo: UploadFile = File(...)
):
    """Upload a training photo for an employee."""
    employee_dir = os.path.join(TRAINING_DIR, f"{employee_id}_{employee_name}")
    if not os.path.exists(employee_dir):
        os.makedirs(employee_dir, exist_ok=True)

    file_extension = Path(photo.filename).suffix.lower()
    if file_extension not in [".jpg", ".jpeg", ".png", ".bmp"]:
        raise HTTPException(status_code=400, detail="Invalid image format. Use JPG, JPEG, PNG, or BMP.")

    existing_photos = len(os.listdir(employee_dir))
    file_path = os.path.join(employee_dir, f"photo_{existing_photos + 1}{file_extension}")

    with open(file_path, "wb") as buffer:
        shutil.copyfileobj(photo.file, buffer)

    # Validate that a face can be detected
    try:
        encodings, locations = encode_face_from_file(file_path)
        if len(encodings) == 0:
            os.remove(file_path)
            raise HTTPException(status_code=400, detail="No face detected in the uploaded photo. Please upload a clear photo with a visible face.")
        if len(encodings) > 1:
            os.remove(file_path)
            raise HTTPException(status_code=400, detail="Multiple faces detected. Please upload a photo with only one face.")
    except HTTPException:
        raise
    except Exception as e:
        if os.path.exists(file_path):
            os.remove(file_path)
        raise HTTPException(status_code=500, detail=f"Error processing image: {str(e)}")

    return {
        "status": "uploaded",
        "employee_id": employee_id,
        "employee_name": employee_name,
        "file_path": file_path,
        "total_photos": existing_photos + 1,
        "face_detected": True
    }


@app.post("/model/train")
async def train_model():
    """Train the facial recognition model on all employee photos."""
    encodings_list = []
    labels_list = []
    employee_stats = {}

    if not os.path.exists(TRAINING_DIR):
        raise HTTPException(status_code=400, detail="No training data directory found.")

    employee_dirs = [d for d in os.listdir(TRAINING_DIR)
                     if os.path.isdir(os.path.join(TRAINING_DIR, d))]

    if len(employee_dirs) < 2:
        raise HTTPException(
            status_code=400,
            detail="Need at least 2 employees with photos to train the model."
        )

    for employee_dir_name in employee_dirs:
        employee_path = os.path.join(TRAINING_DIR, employee_dir_name)
        label = employee_dir_name
        photo_count = 0

        image_files = [f for f in os.listdir(employee_path)
                       if f.lower().endswith(('.jpg', '.jpeg', '.png', '.bmp'))]

        for image_file in image_files:
            image_path = os.path.join(employee_path, image_file)
            try:
                encodings, _ = encode_face_from_file(image_path)
                if len(encodings) > 0:
                    encodings_list.append(encodings[0])
                    labels_list.append(label)
                    photo_count += 1
            except Exception as e:
                logger.warning(f"Error processing {image_path}: {e}")

        employee_stats[label] = photo_count

    if len(encodings_list) < 2:
        raise HTTPException(status_code=400, detail="Not enough valid face encodings found for training.")

    # Check we have at least 2 classes
    unique_labels = set(labels_list)
    if len(unique_labels) < 2:
        raise HTTPException(
            status_code=400,
            detail="Need face encodings from at least 2 different employees."
        )

    # Encode labels
    le = LabelEncoder()
    encoded_labels = le.fit_transform(labels_list)

    # Train SVM with probability calibration
    X = np.array(encodings_list)
    y = encoded_labels

    base_svm = SVC(kernel="rbf", gamma="scale", C=10.0, probability=False)
    # Use CalibratedClassifierCV for better probability estimates
    classifier = CalibratedClassifierCV(base_svm, cv=min(3, min(np.bincount(y))), method="sigmoid")

    try:
        classifier.fit(X, y)
    except ValueError:
        # Fallback to SVC with probability=True if calibration fails
        classifier = SVC(kernel="rbf", gamma="scale", C=10.0, probability=True)
        classifier.fit(X, y)

    # Store model
    face_model["classifier"] = classifier
    face_model["label_encoder"] = le
    face_model["known_encodings"] = encodings_list
    face_model["known_labels"] = labels_list
    face_model["is_trained"] = True

    save_model()

    return {
        "status": "trained",
        "num_employees": len(unique_labels),
        "num_total_images": len(encodings_list),
        "employee_stats": employee_stats,
        "classes": le.classes_.tolist(),
        "timestamp": datetime.now().isoformat()
    }


@app.get("/model/status", response_model=TrainingStatus)
async def model_status():
    """Get current model training status."""
    employees = []
    num_images = 0

    if os.path.exists(TRAINING_DIR):
        for d in os.listdir(TRAINING_DIR):
            dir_path = os.path.join(TRAINING_DIR, d)
            if os.path.isdir(dir_path):
                employees.append(d)
                num_images += len([f for f in os.listdir(dir_path)
                                   if f.lower().endswith(('.jpg', '.jpeg', '.png', '.bmp'))])

    return TrainingStatus(
        status="trained" if face_model["is_trained"] else "untrained",
        num_employees=len(employees),
        num_images=num_images,
        employees=employees
    )


